DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGlateximage.pl",
  "contextFraction.pl",
  "Pd.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Point");
do {
  @a = random_subset(4, 10 .. 90);
  $A = Point((@a)[0,1]);
  $B = Point((@a)[2,3]);
  $D = Vector($B - $A);
} until ($D->norm > 20);
Context("LimitedFraction")->flags->set(allowMixedNumbers => 0, showMixedNumbers => 0);
$m = Fraction($a[3] - $a[1], $a[2] - $a[0]);

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
$image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \begin{axis}[
      xmin=-10,
      ymin=-10,
      xmax=100,
      ymax=100,
      xtick=,
      ytick=,
      minor xtick=,
      minor ytick=,
      width=0.33\orccaprintwidth,
    ]
    \addplot[soliddot] coordinates {$A} node[above] {$A};
    \addplot[soliddot] coordinates {$B} node[above] {$B};
  \end{axis}
\end{tikzpicture}

END_LATEX_IMAGE

############################################################
# Body
############################################################

BEGIN_PGML
Find the rate of change between the two given points.

>> [@image(insertGraph($image_1), width=>600)@]*  <<

[_]{$m}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
